import "server-only";

import { App } from "octokit";

export function createGitHubApp() {
  return new App({
    appId: process.env.GITHUB_APP_ID!,
    privateKey: process.env.GITHUB_PRIVATE_KEY!.replace(/\\n/g, "\n"),
  });
}

export async function POST(request: Request) {
  const event = request.headers.get("x-github-event");
  const delivery = request.headers.get("x-github-delivery");
  const payload = await request.text();

  console.log("verify GitHub webhook before processing", { event, delivery, bytes: payload.length });

  return new Response("ok");
}

const deployChecks = [
  "Create the vendor project and add production env vars",
  "Run the included smoke route after deploy",
  "Document alerting, retries, and rollback behavior",
];

export default function GitHubIntegrationPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">GitHub Integration</h1>
        <p className="text-muted-foreground">GitHub App auth, signed webhooks, and repository automation patterns.</p>
      </div>
      <div className="grid gap-3">
        {deployChecks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
